    #[test]
    fn run_init_rejects_assets_dir_outside_crate() {
        let project = TempProject::new("asset_escape", true);
        let outside_name = format!(
            "{}_outside_assets",
            project
                .path()
                .file_name()
                .expect("temp project name")
                .to_string_lossy()
        );
        let outside = project
            .path()
            .parent()
            .expect("temp project parent")
            .join(&outside_name);
        let _ = test_fs::remove_dir_all(&outside);

        let mut args = default_args(project.path());
        args.assets_dir = PathBuf::from(format!("../{outside_name}/i18n"));
        let err = run_init(args).expect_err("escaping assets_dir should be rejected");
        assert!(err.to_string().contains("--assets-dir"));
        assert!(err.to_string().contains("crate root"));
        assert!(!project.path().join("i18n.toml").exists());
        assert!(!outside.exists());

        let mut args = default_args(project.path());
        args.assets_dir = outside.join("i18n");
        let err = run_init(args).expect_err("absolute assets_dir should be rejected");
        assert!(err.to_string().contains("--assets-dir"));
        assert!(err.to_string().contains("relative"));
        assert!(!project.path().join("i18n.toml").exists());
        assert!(!outside.exists());
    }

