    #[test]
    fn run_init_respects_custom_library_target_path() {
        let project = TempProject::new("custom_library_path", true);
        write_manifest(
            project.path(),
            "[package]\nname = \"custom-lib\"\nversion = \"0.1.0\"\nedition = \"2024\"\n\n[lib]\npath = \"lib.rs\"\n",
        );
        test_fs::write(project.path().join("lib.rs"), "pub fn existing() {}\n")
            .expect("custom lib target should be written");

        run_init(default_args(project.path())).expect("init should respect custom lib target");

        let lib = test_fs::read_to_string(project.path().join("lib.rs"))
            .expect("custom lib target should remain the library file");
        assert!(lib.contains("pub fn existing() {}"));
        assert!(lib.contains("pub mod i18n;"));
        assert!(project.path().join("i18n.rs").exists());
        assert!(!project.path().join("src/lib.rs").exists());
        assert!(!project.path().join("src/i18n.rs").exists());
    }

